<?php

namespace App\Http\Controllers\Vendor;

use App\Http\Controllers\Controller;
use Illuminate\Http\Request;
use Inertia\Inertia;
use App\Models\Invoice;

class InvoiceController extends Controller
{
    public function index(Request $request)
    {
        $eventId = $request->input('event_id');
        $search = $request->input('search');
        $dateFrom = $request->input('date_from');
        $dateTo = $request->input('date_to');

        // 1. Invoices generated BY the vendor FOR the customers
        $customerInvoicesQuery = Invoice::where('vendor_id', auth()->id())
            ->where('type', 'vendor_to_customer')
            ->with(['order.user', 'order.event']);

        if ($eventId) {
            $customerInvoicesQuery->whereHas('order', function ($q) use ($eventId) {
                $q->where('event_id', $eventId);
            });
        }

        if ($search) {
            $customerInvoicesQuery->where(function($q) use ($search) {
                $q->where('invoice_number', 'like', "%{$search}%")
                  ->orWhereHas('order', function($oq) use ($search) {
                      $oq->where('billing_first_name', 'like', "%{$search}%")
                         ->orWhere('billing_last_name', 'like', "%{$search}%")
                         ->orWhere('order_number', 'like', "%{$search}%");
                  });
            });
        }

        if ($dateFrom) {
            $customerInvoicesQuery->whereDate('created_at', '>=', $dateFrom);
        }

        if ($dateTo) {
            $customerInvoicesQuery->whereDate('created_at', '<=', $dateTo);
        }

        $customerInvoices = $customerInvoicesQuery->latest()->get();

        // 2. Invoices generated BY the platform FOR the vendor
        $platformInvoicesQuery = Invoice::where('vendor_id', auth()->id())
            ->where('type', 'platform_to_vendor');

        if ($dateFrom) {
            $platformInvoicesQuery->whereDate('created_at', '>=', $dateFrom);
        }

        if ($dateTo) {
            $platformInvoicesQuery->whereDate('created_at', '<=', $dateTo);
        }

        $platformInvoices = $platformInvoicesQuery->latest()->get();

        $events = auth()->user()->events()->select('id', 'title')->orderBy('title')->get();

        return Inertia::render('Vendor/Invoices/Index', [
            'customerInvoices' => $customerInvoices,
            'platformInvoices' => $platformInvoices,
            'events' => $events,
            'filters' => [
                'event_id' => $eventId,
                'search' => $search,
                'date_from' => $dateFrom,
                'date_to' => $dateTo,
            ]
        ]);
    }

    public function download(Invoice $invoice)
    {
        if ($invoice->vendor_id !== auth()->id()) abort(403);
        
        return \Illuminate\Support\Facades\Storage::disk('public')->download($invoice->pdf_path, $invoice->invoice_number . '.pdf');
    }
}
